import {Question, Answer} from './QuestionsInterfaces';
import jibo = require('jibo');

//String present in WotDPuzzle.rule to be replaced dynamically
const RIGHT_WORD:string = 'WOTD_DYNAMIC_RIGHT_ANSWER';
const DECOY_ONE:string = 'WOTD_DYNAMIC_DECOY_ONE';
const DECOY_TWO:string = 'WOTD_DYNAMIC_DECOY_TWO';

const SUFFIXES = '(?:d|s|ed|es|\'s|ing)?';

export class Rule {
    private right:RegExp;
    private decoys:RegExp[];
    constructor(right:RegExp, decoys:RegExp[]) {
        this.right = right;
        this.decoys = decoys;
    }
    
    public parse(input: string): string {
        if (this.right.test(input)) {
            return 'right';
        }
        for (let i = 0; i < this.decoys.length; ++i) {
            if (this.decoys[i].test(input)) {
                return `decoy${i+1}`;
            }
        }
        return 'noMatch';
    }
}

export default class RuleGenerator {

    public generateRule(question:Question):Rule {
        let rightAnswer:Answer;
        let decoys:Answer[] = [];
        for(let answer of question.answers){
            if(answer.correct){
                rightAnswer = answer;
            }
            else{
                decoys.push(answer);
            }
        }
        return new Rule(this._buildRegex(rightAnswer), decoys.map(decoy => this._buildRegex(decoy)));
    }

    private _buildRegex(answer:Answer) {
        return new RegExp(`\\b(?:${this._buildWordList(answer)})${SUFFIXES}\\b`, 'i');
    }

    private _buildWordList(answer:Answer){
        let result = answer.answer;
        if(answer.homophones && answer.homophones.length){
            for(let phrase of answer.homophones){
                result += `|${phrase}`;
            }
        }
        return result;
    }

}
