/// <reference path="../typings/index.d.ts" />
import jibo = require('jibo');
import { BeSkill, Options, libraries } from '@be/be-framework';
import PromiseUtils = libraries.jibo_cai_utils.PromiseUtils;
import CancelTokenSession = libraries.jibo_cai_utils.CancelTokenSession;
import { SurpriseElement, LaunchContext } from '@be/surprises';
import QuestionSelector from './QuestionSelector';
import RuleGenerator from './RuleGenerator';
import VerticalListView from './VerticalListView';
import Analytics from './analytics/Analytics';

const MainFlow = require('./flows/Main.flow');

const MINUTES_TO_MS = 60 * 1000;
const HOURS_TO_MS = 60 * MINUTES_TO_MS;

const MIN_LOOP_AGE_FOR_OFFER = 18;//hours after loop is created to allow proactive offer

export default class WordOfTheDay extends SurpriseElement {

    private _flow: jibo.flow.FlowExecutor
    private _session: CancelTokenSession;

    private _mainModel: jibo.kb.Model;
    private _mainRoot: jibo.kb.Node;// data: {lastPlayed:number, lastOffered:number}
    private _playedModel: jibo.kb.Model;

    private _questionSelector: QuestionSelector;
    private _ruleGenerator: RuleGenerator;

    /** time when skill was launched - use for consistency of logic when skill crosses date boundaries (midnight) */
    private _thisTime:number;

    private _launchIntent:string;

    private _jiboBirthday:number;

    /**
     * WordOfTheDay skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack?: Options) {
        super(assetPack);
    }

    getCategoryPriority(){
        return 5;
    }

    async getContextualPriority(context: LaunchContext) {
        let currentDate:Date = new Date();
        let currentHour:number = currentDate.getHours();
        //if time of day is between 10 PM and 12 PM, return 0
        if (currentHour >= 22 || currentHour < 12) {
            return 0;
        }
        let today:string = currentDate.toDateString();
        let lastOffered:string = new Date(this._mainRoot.data.lastOffered || 0).toDateString();
        let lastPlayed:string = new Date(this._mainRoot.data.lastPlayed || 0).toDateString();
        //if played or offered already on today's date, return 0
        if (lastOffered === today || lastPlayed === today) {
            return 0;
        }
        //if age of loop is less than 18 hours, return 0
        if ((currentDate.getTime() - this._jiboBirthday) / HOURS_TO_MS < MIN_LOOP_AGE_FOR_OFFER) {
            return 0;
        }
        //else if time of day is between 12PM and 10PM, return 1
        return 1;
    }

    postInit(done) {
        this._mainModel = jibo.kb.createModel('/word-of-the-day');
        this._playedModel = this._mainModel.createModel('played-words');
        this._mainModel.loadRoot().then((root)=>{ this._mainRoot = root;})
        .catch((err)=>{this.log.error('failed to load main root node', err)})
        .then(() => {
            return jibo.kb.loop.loadLoop()
            .then((loop) => {
                for (let user of loop) {
                    if (user.isJibo) {
                        this._jiboBirthday = user.created;
                        break;
                    }
                }
            })
            .catch((err) => {
                this.log.error('Error creating loop in Surprise Element', err);
                this._jiboBirthday = 0;
            });
        })
        .then(done);

    }

    preload(done: (err?: any) => void): void {
        jibo.face.views.creator.registerClass(VerticalListView, 'VerticalListView');
        this._thisTime = Date.now();
        this._ruleGenerator = new RuleGenerator();
        this._questionSelector = new QuestionSelector(this.log);
        this._questionSelector.init(this._playedModel, this._mainRoot, this._thisTime)
        .catch((err)=>{
            //TODO: figure out how to report error to user
            this.log.error('preload failed', err);
        })
        .then(()=>{done();});
    }

    /**
     * Start the skill
     * @method open
     */
    open(result: any, refresh: boolean, previousSkillName: string): void {
        jibo.mim.silentMenus = false;//TODO: this is a hack to never disable listening at ORs
        if(result && result.nlu && result.nlu.intent){
            this._launchIntent = result.nlu.intent;
            if(this._launchIntent === 'menu'){
                this._launchIntent = 'play';
            }
        }
        else{
            this._launchIntent = 'surprise';
        }
        Analytics.init(this);
        this._mainRoot.data.lastOffered = this._thisTime;

        let promises:Promise<void>[] = [ this._forceEye() ];
        if(this._flow){
            promises.push(this._flow.stopAndDestroy().then(()=>{this._flow = null;}));
        }
        this._session = new CancelTokenSession();
            this._session.wrap(this.promiseEvery(promises)).then(this._runFlow, this._runFlow);
    }

    private _runFlow = () => {
        this._session = null;
        const playedToday = new Date(this._mainRoot.data.lastPlayed).toDateString() === new Date(this._thisTime).toDateString();
        let options = {
            assetPack: this.assetPack,
            blackboard: {
                Analytics: Analytics,
                questionSelector: this._questionSelector,
                ruleGenerator: this._ruleGenerator,
                playedToday,
                forceEye:this._forceEye,
                intent:this._launchIntent,
                log:this.log
            }
        };
        this._flow = jibo.flow.run(MainFlow, options, (err, status) => {
            if (status === jibo.bt.Status.INTERRUPTED) {
                return;
            }
            this.exit();
        });
    }

    private _forceEye():Promise<void>{
        return new Promise((resolve)=>{
            jibo.face.views.forceEyeView(
                () => {
                    resolve();
                },
                null, // onLoaded callback
                null, // use default transitionOpen
                null, // use default transitionClose
                (err) => {
                    this.log.warn('Failed reseting view', err);
                    resolve();
                });
        });
    }

    /**
     * Stop and unload the skill
     * @method close
     */
    close(done: () => void): void {
        jibo.face.views.creator.unregisterClass('VerticalListView');
        let promises:Promise<void>[] = [];
        if(this._session){
            promises.push(this._session.cancel());
            this._session = null;
        }
        if(this._questionSelector){
            this._questionSelector.destroy()
            this._questionSelector = null;
        }
        if(this._flow){
            promises.push(this._flow.stopAndDestroy());
            this._flow = null;
        }
        promises.push(this._mainRoot.save());
        this.promiseEvery(promises).then(()=>{done();}, done);
    }

    private promiseEvery(promises:Promise<any>[]):Promise<any[]>{
        let rejected = false;
        let allPromises: Promise<any>[] = new Array(promises.length);
        let results: any[] = new Array(promises.length);
        for(let i = 0; i < promises.length; i++){
            allPromises.push(
                new Promise((resolve)=>{
                    promises[i]
                        .then((result)=>{results[i] = result;})
                        .catch((error)=>{
                            results[i] = error;
                            rejected = true;
                        })
                        .then(resolve);
                })
            );
        }
        return new Promise((resolve, reject)=>{
            Promise.all(allPromises).then(()=>{
                if(rejected){
                    reject(results);
                }
                else{
                    resolve(results);
                }
            });
        });
    }
}
