import jibo = require('jibo');

import ActionData = jibo.rendering.gui.actions.ActionData;
import Button = jibo.face.views.Button;
import View = jibo.rendering.gui.views.View;

export default class VerticalListView extends View {

    constructor(viewState) {
        super(viewState);
    }

    public actionEnactor(action:jibo.rendering.gui.actions.ActionData):boolean{
        if(action.type === ActionData.VERBAL_COMMAND && action.data.intent === 'selectItem'){
            let buttonId = null;
            switch(action.data.entities.itemPosition){
                case 'first':
                case 'top':
                    buttonId = 'answerButton1';
                    break;
                case 'middle':
                case 'second':
                    buttonId = 'answerButton2';
                    break;
                case 'last':
                case 'third':
                case 'bottom':
                    buttonId = 'answerButton3';
                    break;
            }
            if(buttonId){
                let buttonToPress:Button = this.getComponentById(buttonId) as Button;
                if(buttonToPress){
                    buttonToPress.activate();
                    buttonToPress.triggerActions(jibo.face.views.GESTURE.TAP);
                    return true;
                }
            }
        }
        return super.actionEnactor(action);
    }
}
